import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Award, Clock, Shield, Check } from 'lucide-react';

// Try both import paths to see which works
// If layout path doesn't work, use the original paths
import Navbar from '../components/layout/Navbar';  
import Footer from '../components/layout/Footer';

const MarketingHome = () => {
  const [email, setEmail] = useState('');
  const navigate = useNavigate();
  
  // Log when component mounts to verify it's being rendered
  useEffect(() => {
    console.log('MarketingHome component mounted');
  }, []);
  
  const handleSignup = (e) => {
    e.preventDefault();
    console.log('Form submitted with email:', email);
    localStorage.setItem('signupEmail', email);
    navigate('/register');
  };

  return (
    <div className="bg-gray-50 min-h-screen">
      {/* Try wrapping Navbar in error boundary */}
      <div className="relative z-50">
        <Navbar />
      </div>
      
      {/* Add some debugging content to see if the component renders at all */}
      <div className="pt-16" id="content-start">
        {/* Rest of your content */}
        
        {/* Hero Section */}
        <section className="bg-gradient-to-r from-blue-600 to-blue-800 text-white rounded-lg overflow-hidden shadow-xl mb-12 mx-4 md:mx-8 lg:mx-auto lg:max-w-7xl">
          {/* Your hero section content */}
        </section>

        {/* Other sections */}
      </div>
      
      <Footer />
    </div>
  );
};

export default MarketingHome;
